import{_ as e,r as n,o as s,c as d,b as t,d as i,a as r,e as l}from"./app.521b9759.js";const o={},c=l(`<h1 id="mysql的四种事务隔离级别" tabindex="-1"><a class="header-anchor" href="#mysql的四种事务隔离级别" aria-hidden="true">#</a> MySQL的四种事务隔离级别</h1><h2 id="事务的基本要素-acid" tabindex="-1"><a class="header-anchor" href="#事务的基本要素-acid" aria-hidden="true">#</a> 事务的基本要素（ACID）</h2><ol><li><p>原子性（Atomicity）：事务开始后所有操作，要么全部做完，要么全部不做，不可能停滞在中间环节。事务执行过程中出错，会回滚到事务开始前的状态，所有的操作就像没有发生一样。也就是说事务是一个不可分割的整体，就像化学中学过的原子，是物质构成的基本单位。</p></li><li><p>一致性（Consistency）：事务开始前和结束后，数据库的完整性约束没有被破坏 。比如A向B转账，不可能A扣了钱，B却没收到。</p></li><li><p>隔离性（Isolation）：同一时间，只允许一个事务请求同一数据，不同的事务之间彼此没有任何干扰。比如A正在从一张银行卡中取钱，在A取钱的过程结束前，B不能向这张卡转账。</p></li><li><p>持久性（Durability）：事务完成后，事务对数据库的所有更新将被保存到数据库，不能回滚。</p></li></ol><h2 id="事务的并发问题" tabindex="-1"><a class="header-anchor" href="#事务的并发问题" aria-hidden="true">#</a> 事务的并发问题</h2><ol><li><p>脏读：事务A读取了事务B更新的数据，然后B回滚操作，那么A读取到的数据是脏数据</p></li><li><p>不可重复读：事务 A 多次读取同一数据，事务 B 在事务A多次读取的过程中，对数据作了更新并提交，导致事务A多次读取同一数据时，结果 不一致。</p></li><li><p>幻读：系统管理员A将数据库中所有学生的成绩从具体分数改为ABCDE等级，但是系统管理员B就在这个时候插入了一条具体分数的记录，当系统管理员A改结束后发现还有一条记录没有改过来，就好像发生了幻觉一样，这就叫幻读。</p></li></ol><div class="custom-container tip"><p class="custom-container-title">小结</p><p><strong>不可重复读</strong>的和<strong>幻读</strong>很容易混淆，<strong>不可重复读侧重于修改，幻读侧重于新增或删除。解决不可重复读的问题只需锁住满足条件的行，解决幻读需要锁表</strong></p></div><h2 id="mysql事务隔离级别" tabindex="-1"><a class="header-anchor" href="#mysql事务隔离级别" aria-hidden="true">#</a> MySQL事务隔离级别</h2><table><thead><tr><th>事务隔离级别</th><th>脏读</th><th>不可重复读</th><th>幻读</th></tr></thead><tbody><tr><td>读未提交（read-uncommitted）</td><td>是</td><td>是</td><td>是</td></tr><tr><td>不可重复读（read-committed）</td><td>否</td><td>是</td><td>是</td></tr><tr><td>可重复读（repeatable-read）</td><td>否</td><td>否</td><td>是</td></tr><tr><td>串行化（serializable）</td><td>否</td><td>否</td><td>否</td></tr></tbody></table><p>mysql默认的事务隔离级别为repeatable-read</p><p>MySQL查询事务隔离级别用transaction_isolation，tx_isolation在MySQL 5.7.20后被弃用。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> @<span class="token variable">@transaction_isolation</span>

@<span class="token variable">@transaction_isolation</span>
<span class="token comment">-----------------------</span>
<span class="token keyword">REPEATABLE</span><span class="token operator">-</span><span class="token keyword">READ</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="相关链接" tabindex="-1"><a class="header-anchor" href="#相关链接" aria-hidden="true">#</a> 相关链接</h2>`,12),p={href:"https://www.cnblogs.com/huanongying/p/7021555.html",target:"_blank",rel:"noopener noreferrer"};function h(m,u){const a=n("ExternalLinkIcon");return s(),d("div",null,[c,t("p",null,[t("a",p,[i("MySQL的四种事务隔离级别"),r(a)])])])}const v=e(o,[["render",h],["__file","mysql-isolation-level.html.vue"]]);export{v as default};
